changeSet.sql:
ALTER TABLE campaign_npcs
    ADD COLUMN source_type       varchar(20) NULL,
    ADD COLUMN race_id           uuid        NULL REFERENCES character_races(id),
    ADD COLUMN class_id          uuid        NULL REFERENCES character_classes(id),
    ADD COLUMN level             integer     NULL,
    ADD COLUMN abilities         text        NULL,
    ADD COLUMN source_monster_id uuid        NULL REFERENCES monsters(id);

CREATE INDEX idx_npc_race_id           ON campaign_npcs (race_id);
CREATE INDEX idx_npc_class_id          ON campaign_npcs (class_id);
CREATE INDEX idx_npc_source_monster_id ON campaign_npcs (source_monster_id);

CREATE TABLE campaign_npc_spells (
    npc_id   uuid NOT NULL REFERENCES campaign_npcs(id) ON DELETE CASCADE,
    spell_id uuid NOT NULL REFERENCES spells(id),
    PRIMARY KEY (npc_id, spell_id)
);
CREATE INDEX idx_npc_spells_spell_id ON campaign_npc_spells (spell_id);
